# generated by AI in Github cloud
from __future__ import annotations

from dataclasses import dataclass
from datetime import date


@dataclass(frozen=True)
class Greeting:
    recipient: str
    message: str

    def __post_init__(self) -> None:
        if self.recipient is None or not self.recipient.strip():
            raise ValueError("recipient must not be blank")
        if self.message is None or not self.message.strip():
            raise ValueError("message must not be blank")

    def formatted(self) -> str:
        return (
            "╔══════════════════════════════╗\n"
            f"║  {self.message}, {self.recipient}!  ║\n"
            "╚══════════════════════════════╝\n"
        )


def time_of_day(hour: int) -> str:
    return "morning" if hour < 12 else "afternoon" if hour < 17 else "evening"


def salutation_for(hour: int) -> str:
    return {
        "morning": "Good morning",
        "afternoon": "Good afternoon",
        "evening": "Good evening",
    }[time_of_day(hour)]


def season_of(month: int) -> str:
    if month in (12, 1, 2):
        return "Winter"
    if month in (3, 4, 5):
        return "Spring"
    if month in (6, 7, 8):
        return "Summer"
    return "Autumn"


def build_output(today: date | None = None) -> str:
    current_day = today or date.today()
    greeting = Greeting("World", salutation_for(current_day.day % 24))
    return (
        greeting.formatted()
        + "Python version : 3\n"
        + f"Today's date : {current_day} ({season_of(current_day.month)})\n"
    )


def main() -> None:
    print(build_output(), end="")


if __name__ == "__main__":
    main()
